// Surface each conjunct of HostState::next_ensures as a separate implication
// at both r1 and r2 so z3 sees the inner spec terms (ok, view, event_seq,
// well_typed_events) at concrete arguments for both runs side-by-side. Each
// of these `assert(A ==> B)` obligations follows by direct unfolding of the
// `pub open spec fn next_ensures` body, so Verus must verify it.
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> r1.0 == post1_netc.ok());
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> r2.0 == post2_netc.ok());

assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (r1.0 ==> post1_self_.invariants(&post1_netc.my_end_point())));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (r2.0 ==> post2_self_.invariants(&post2_netc.my_end_point())));

assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (r1.0 ==> HostState::next(pre_self_.view(), post1_self_.view(), (r1.1)@.ios)));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (r2.0 ==> HostState::next(pre_self_.view(), post2_self_.view(), (r2.1)@.ios)));

assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (r1.0 ==> (r1.1)@.event_seq() == (r1.1)@.ios));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (r2.0 ==> (r2.1)@.event_seq() == (r2.1)@.ios));

assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> ((r1.0 || (r1.1)@.sends.len() > 0)
        ==> post1_netc.history() == pre_netc.history() + (r1.1)@.event_seq()));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> ((r2.0 || (r2.1)@.sends.len() > 0)
        ==> post2_netc.history() == pre_netc.history() + (r2.1)@.event_seq()));

assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (r1.1)@.well_typed_events());
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (r2.1)@.well_typed_events());

// Touch the components of det_receive_packet_next_equal at the exact tuple
// from the postcondition so its inner triggers line up with the next_ensures
// trigger terms above.
assert((r1.1)@.recvs =~= (r1.1)@.recvs);
assert((r1.1)@.clocks =~= (r1.1)@.clocks);
assert((r1.1)@.sends =~= (r1.1)@.sends);
assert((r2.1)@.recvs =~= (r2.1)@.recvs);
assert((r2.1)@.clocks =~= (r2.1)@.clocks);
assert((r2.1)@.sends =~= (r2.1)@.sends);

// View-level identities — bring the .view() projections of the post states
// and the netc views into the e-graph at the exact terms used by
// det_receive_packet_next_equal.
assert(post1_self_.view() == post1_self_.view());
assert(post2_self_.view() == post2_self_.view());
assert(post1_netc.view() == post1_netc.view());
assert(post2_netc.view() == post2_netc.view());

// Finally pull both next_ensures and det_..._equal goal terms in alongside
// each other so the outer-level trigger correspondence is also present.
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    == HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    == HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2));
assert(det_receive_packet_next_equal(r1, r2, post1_self_@, post2_self_@, post1_netc, post2_netc)
    == det_receive_packet_next_equal(r1, r2, post1_self_@, post2_self_@, post1_netc, post2_netc));
